/**
 * Workspace Scheduler Proposal V1 — the governed scheduler-provider lane,
 * modeled one-to-one on the resolver studio (lib/workspace-resolver-proposal.js).
 *
 * A resolver shapes an API response into rows; a scheduler provisions a
 * persistent, recurring serverless run. Both are SERVER ARTIFACTS, not workspace
 * config — so this lane uses the same boundary:
 *
 *   - type "scheduler.create", affectedField "server-file" (never a PATCH key)
 *   - the generated file is confined to lib/adapters/integrations/schedulers/
 *   - the provider secret is read from server env at run time via authRef
 *     candidate keys — never inlined
 *   - it emits a receipt; "state → eligibility → guidance → action → evidence"
 *     closes exactly as the resolver lane does
 *
 * The generated artifact is the externalized endpoint the user deploys (a
 * Supabase Edge Function, or the destination a QStash schedule POSTs to). The
 * proposal also carries:
 *   - `registryBinding` — the api-registry "scheduler" row the serverless
 *     delegation (sandbox-run via schedulerRegistryId) will target, and
 *   - `scheduleSpec` — the cron the provision route registers with the provider.
 *
 * This module is PURE (build/validate/generate). The confined fs write lives in
 * lib/server-scheduler-write.js (server-only). Secret-safe: ids/slugs/cron only.
 */

import { cadenceToCron, normalizeCadence } from "./scheduler-cadence.js";

const SCHEDULER_PROPOSAL_TYPE = "scheduler.create";
const SCHEDULER_AFFECTED_FIELD = "server-file";
const SCHEDULER_DIR = "lib/adapters/integrations/schedulers";
const SCHEDULER_PROVIDERS = Object.freeze(["supabase-edge", "qstash-schedule"]);
const SCHEDULER_CONNECTOR_KIND = "scheduler";

function clean(value) {
  return String(value == null ? "" : value).trim();
}

function slugify(value, fallback = "scheduler") {
  const slug = clean(value)
    .toLowerCase()
    .replace(/\.js$/, "")
    .replace(/[^a-z0-9-]/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 64);
  return slug || fallback;
}

function envCandidates(ref) {
  const token = clean(ref).replace(/[^a-z0-9]+/gi, "_").replace(/^_+|_+$/g, "").toUpperCase();
  if (!token) return [];
  return Array.from(new Set([token, `${token}_API_KEY`, `${token}_TOKEN`]));
}

function normalizeProvider(value) {
  const v = clean(value).toLowerCase();
  return SCHEDULER_PROVIDERS.includes(v) ? v : "supabase-edge";
}

/**
 * Confine a scheduler filename to the scheduler dir. Mirrors the resolver
 * write's traversal guard so the studio previews exactly what the write accepts.
 */
function resolveSchedulerFilePath(integrationId, provider) {
  const base = `${slugify(integrationId, "scheduler")}-${normalizeProvider(provider)}`;
  if (base.includes("/") || base.includes("..")) {
    return { ok: false, path: null, filename: null, dir: SCHEDULER_DIR, error: "scheduler filename must not contain path segments" };
  }
  const filename = `${base}.js`;
  return { ok: true, path: `${SCHEDULER_DIR}/${filename}`, filename, dir: SCHEDULER_DIR, error: null };
}

function safeJsString(value) {
  return JSON.stringify(clean(value));
}

/**
 * Generate the deployable provider endpoint for a specific schedule. The secret
 * is read from the host runtime env via the authRef candidate keys at run time —
 * never inlined. The handler accepts the same `growthub-sandbox-run-v1` envelope
 * the serverless delegation already sends, so either locality normalizes
 * identically downstream.
 */
function generateSchedulerEndpointCode({ provider, integrationId, cron, cadence, authRef }) {
  const id = slugify(integrationId, "scheduler");
  const p = normalizeProvider(provider);
  const candidates = envCandidates(authRef || id);
  const cadenceNorm = normalizeCadence(cadence);
  const cronText = clean(cron);

  if (p === "supabase-edge") {
    return `// Supabase Edge Function for "${id}" — generated by the governed scheduler studio.
// Deploy: copy to supabase/functions/${id}/index.js, then \`supabase functions deploy ${id}\`.
// Schedule (cadence "${cadenceNorm}"${cronText ? `, cron "${cronText}"` : ""}) is registered with the
// provider by POST /api/workspace/scheduler/provision — this file is the destination it invokes.
// Reads its shared secret from the Edge env (candidates: ${candidates.join(", ") || "none"}); never hard-code a secret here.
const ENV_CANDIDATES = ${JSON.stringify(candidates)};
function readSecret(env) {
  for (const key of ENV_CANDIDATES) {
    const value = env.get(key);
    if (value) return value;
  }
  return "";
}

Deno.serve(async (req) => {
  const json = (body, status = 200) => new Response(JSON.stringify(body), { status, headers: { "content-type": "application/json" } });
  const secret = readSecret(Deno.env);
  if (secret) {
    const header = req.headers.get("authorization") || req.headers.get("x-api-key") || "";
    if (!header.includes(secret)) return json({ ok: false, exitCode: 1, error: "unauthorized" }, 401);
  }
  let body;
  try { body = await req.json(); } catch { return json({ ok: false, exitCode: 1, error: "invalid JSON body" }, 400); }
  if (body?.kind !== "growthub-sandbox-run-v1") {
    return json({ ok: false, exitCode: 1, error: "expected growthub-sandbox-run-v1 envelope" }, 400);
  }
  // ── Your scheduled work goes here. \`body.sandbox.command\` / \`body.sandbox.instructions\`
  //    carry the workflow payload; \`body.runId\` is the stable run id. Return the
  //    sandbox-run result shape so the workspace normalizes it identically to a local run.
  return json({ ok: true, exitCode: 0, stdout: \`scheduled run \${body.runId || ""} accepted by ${id}\`, durationMs: 0 });
});
`;
  }

  // qstash-schedule: the destination QStash POSTs to on the cron schedule.
  return `// QStash schedule destination for "${id}" — generated by the governed scheduler studio.
// Deploy this as an HTTP endpoint (Next.js route / serverless function). QStash is
// pointed at its public URL and registered with cron "${cronText || "<set by provision>"}"
// (cadence "${cadenceNorm}") by POST /api/workspace/scheduler/provision.
// Verify the Upstash-Signature in production; the secret is read from server env
// at run time (candidates: ${candidates.join(", ") || "none"}); never hard-code it here.
const ENV_CANDIDATES = ${JSON.stringify(candidates)};
function readSecret() {
  for (const key of ENV_CANDIDATES) {
    if (process.env[key]) return process.env[key];
  }
  return "";
}

export async function POST(request) {
  const secret = readSecret();
  if (secret) {
    const header = request.headers.get("authorization") || request.headers.get("x-api-key") || "";
    if (!header.includes(secret)) return Response.json({ ok: false, exitCode: 1, error: "unauthorized" }, { status: 401 });
  }
  let body;
  try { body = await request.json(); } catch { return Response.json({ ok: false, exitCode: 1, error: "invalid JSON body" }, { status: 400 }); }
  if (body?.kind !== "growthub-sandbox-run-v1") {
    return Response.json({ ok: false, exitCode: 1, error: "expected growthub-sandbox-run-v1 envelope" }, { status: 400 });
  }
  // ── Your scheduled work goes here. Return the sandbox-run result shape.
  return Response.json({ ok: true, exitCode: 0, stdout: \`qstash scheduled run \${body.runId || ""} accepted by ${id}\`, durationMs: 0 });
}

export const dynamic = "force-dynamic";
`;
}

/**
 * Build an inert scheduler.create proposal. Carries the target artifact path,
 * the generated endpoint code, the api-registry binding the serverless
 * delegation will target, and the cron the provision route registers. Nothing
 * is written or scheduled until the provision lane runs (gated + confirm-200).
 */
function buildSchedulerProposal(input = {}) {
  const integrationId = slugify(input.integrationId, "scheduler");
  const provider = normalizeProvider(input.provider);
  const cadence = normalizeCadence(input.cadence);
  const { cron, error: cronError } = cadenceToCron(cadence, { cron: input.cron });
  const authRef = clean(input.authRef) || integrationId.replace(/-/g, "_").toUpperCase();
  const target = resolveSchedulerFilePath(integrationId, provider);
  const code = generateSchedulerEndpointCode({ provider, integrationId, cron, cadence, authRef });

  return {
    type: SCHEDULER_PROPOSAL_TYPE,
    affectedField: SCHEDULER_AFFECTED_FIELD,
    rationale: `Provision a ${provider} scheduler for "${integrationId}" running ${cadence}${cron ? ` (${cron})` : ""}.`,
    confidence: 0.85,
    target,
    language: "javascript",
    code,
    security: [
      "Server artifact — only written in filesystem mode (read-only runtimes get a 409 + guidance).",
      "Reads its secret from the runtime env at run time via authRef candidates; never inlines a value.",
      `Path confined to ${SCHEDULER_DIR}.`,
    ],
    contract: {
      inputs: [`cadence "${cadence}"`, cron ? `cron "${cron}"` : "no cron (manual)", `authRef env (${envCandidates(authRef).join(", ") || "none"})`],
      output: "An HTTP endpoint that accepts growthub-sandbox-run-v1 and returns the sandbox-run result shape.",
    },
    // The api-registry "scheduler" row the serverless delegation will target via
    // schedulerRegistryId. Credentials stay as an authRef name only.
    registryBinding: {
      integrationId,
      connectorKind: SCHEDULER_CONNECTOR_KIND,
      schedulerProvider: provider,
      method: "POST",
      authRef,
      baseUrl: clean(input.baseUrl),
      endpoint: clean(input.endpoint),
      cronExpression: cron || "",
    },
    // What the provision route registers with the provider.
    scheduleSpec: {
      provider,
      cadence,
      cron: cron || null,
      cronError: cronError || null,
      timezone: clean(input.timezone) || "UTC",
    },
    payload: {
      integrationId,
      provider,
      cadence,
      cron: cron || "",
      authRef,
      filename: target.filename,
    },
  };
}

/**
 * Validate a scheduler.create proposal before the provision lane writes it.
 * Returns { ok, error, target }.
 */
function validateSchedulerProposal(proposal) {
  if (!proposal || proposal.type !== SCHEDULER_PROPOSAL_TYPE) {
    return { ok: false, error: "not a scheduler.create proposal" };
  }
  if (proposal.affectedField !== SCHEDULER_AFFECTED_FIELD) {
    return { ok: false, error: `scheduler.create affectedField must be "${SCHEDULER_AFFECTED_FIELD}"` };
  }
  const provider = normalizeProvider(proposal.payload?.provider || proposal.scheduleSpec?.provider);
  if (!SCHEDULER_PROVIDERS.includes(clean(proposal.payload?.provider || proposal.scheduleSpec?.provider).toLowerCase())) {
    return { ok: false, error: `scheduler provider must be one of ${SCHEDULER_PROVIDERS.join(", ")}` };
  }
  const target = (proposal.target && proposal.target.ok)
    ? proposal.target
    : resolveSchedulerFilePath(proposal.payload?.integrationId, provider);
  if (!target || !target.ok) {
    return { ok: false, error: target?.error || "invalid scheduler target path" };
  }
  const code = clean(proposal.code);
  if (!code) return { ok: false, error: "scheduler code is empty" };
  if (!target.filename.endsWith(".js")) {
    return { ok: false, error: "scheduler file must have a .js extension" };
  }
  if (proposal.scheduleSpec?.cronError) {
    return { ok: false, error: proposal.scheduleSpec.cronError };
  }
  return { ok: true, error: null, target };
}

export {
  SCHEDULER_PROPOSAL_TYPE,
  SCHEDULER_AFFECTED_FIELD,
  SCHEDULER_DIR,
  SCHEDULER_PROVIDERS,
  SCHEDULER_CONNECTOR_KIND,
  normalizeProvider,
  resolveSchedulerFilePath,
  generateSchedulerEndpointCode,
  buildSchedulerProposal,
  validateSchedulerProposal,
  envCandidates,
};
